import os

# src/store/canvas.js
content = "import { create } from 'zustand';\n\nexport const useCanvasStore = create((set) => ({\n  // Product cards: { canvasId: [{ id, product, x, y, ownerId }] }\n  cards: {},\n\n  addCard: (canvasId, card) => set(state => ({\n    cards: {\n      ...state.cards,\n      [canvasId]: [...(state.cards[canvasId] || []), card]\n    }\n  })),\n\n  moveCard: (canvasId, cardId, x, y) => set(state => ({\n    cards: {\n      ...state.cards,\n      [canvasId]: (state.cards[canvasId] || []).map(c =>\n        c.id === cardId ? { ...c, x, y } : c\n      )\n    }\n  })),\n\n  removeCard: (canvasId, cardId, userId) => set(state => ({\n    cards: {\n      ...state.cards,\n      [canvasId]: (state.cards[canvasId] || []).filter(c =>\n        !(c.id === cardId && c.ownerId === userId)\n      )\n    }\n  })),\n\n  // Emoji stickers: { canvasId: [{ id, emoji, x, y, ownerId }] }\n  stickers: {},\n\n  addSticker: (canvasId, sticker) => set(state => ({\n    stickers: {\n      ...state.stickers,\n      [canvasId]: [...(state.stickers[canvasId] || []), sticker]\n    }\n  })),\n\n  moveSticker: (canvasId, stickerId, x, y) => set(state => ({\n    stickers: {\n      ...state.stickers,\n      [canvasId]: (state.stickers[canvasId] || []).map(s =>\n        s.id === stickerId ? { ...s, x, y } : s\n      )\n    }\n  })),\n\n  removeSticker: (canvasId, stickerId, userId) => set(state => ({\n    stickers: {\n      ...state.stickers,\n      [canvasId]: (state.stickers[canvasId] || []).filter(s =>\n        !(s.id === stickerId && s.ownerId === userId)\n      )\n    }\n  })),\n\n  // Recording state: { canvasId: { userId, userName } | null }\n  recording: {},\n\n  setRecording: (canvasId, userInfo) => set(state => ({\n    recording: { ...state.recording, [canvasId]: userInfo }\n  })),\n\n  clearRecording: (canvasId) => set(state => ({\n    recording: { ...state.recording, [canvasId]: null }\n  })),\n}));\n"
os.makedirs(r"src\\store", exist_ok=True)
open(r"src\\store\\canvas.js", "w", encoding="utf-8").write(content)
print("Done: src/store/canvas.js")

# src/hooks/useProductDrop.js
content = "import { useCanvasStore } from '../store/canvas';\nimport { useAuthStore } from '../store/auth';\n\nexport function useProductDrop(canvasId, containerRef) {\n  const addCard = useCanvasStore(s => s.addCard);\n  const user    = useAuthStore(s => s.user);\n  const userId  = user?.id || 'guest-' + Math.random().toString(36).slice(2, 7);\n\n  const onDragOver = (e) => {\n    e.preventDefault();\n    e.dataTransfer.dropEffect = 'copy';\n  };\n\n  const onDrop = (e) => {\n    e.preventDefault();\n    const raw = e.dataTransfer.getData('application/drawnbuy-product');\n    if (!raw) return;\n    let product;\n    try { product = JSON.parse(raw); } catch { return; }\n\n    const rect = containerRef.current?.getBoundingClientRect();\n    if (!rect) return;\n\n    const x = Math.max(0, e.clientX - rect.left - 80);\n    const y = Math.max(0, e.clientY - rect.top  - 60);\n\n    addCard(canvasId, {\n      id: Date.now().toString(),\n      product,\n      x,\n      y,\n      ownerId: userId,\n    });\n  };\n\n  return { onDragOver, onDrop };\n}\n"
os.makedirs(r"src\\hooks", exist_ok=True)
open(r"src\\hooks\\useProductDrop.js", "w", encoding="utf-8").write(content)
print("Done: src/hooks/useProductDrop.js")

# src/components/ProductCard.jsx
content = "import { useState, useRef } from 'react';\nimport { useCanvasStore } from '../store/canvas';\nimport { useAuthStore } from '../store/auth';\n\nconst safeOpen = (url) => {\n  if (!url) return;\n  const trusted = ['amazon.co.uk','amazon.com','ikea.com','zalando.com','nike.com','boots.com'];\n  try {\n    const host = new URL(url).hostname.replace('www.','');\n    if (trusted.some(d => host.endsWith(d))) window.open(url, '_blank', 'noopener,noreferrer');\n    else window.open('https://www.amazon.co.uk/s?k='+encodeURIComponent(url), '_blank', 'noopener,noreferrer');\n  } catch {}\n};\n\nexport default function ProductCard({ card, canvasId }) {\n  const moveCard   = useCanvasStore(s => s.moveCard);\n  const removeCard = useCanvasStore(s => s.removeCard);\n  const user       = useAuthStore(s => s.user);\n  const userId     = user?.id || '';\n  const isOwner    = card.ownerId === userId || card.ownerId?.startsWith('guest');\n\n  const dragStart = useRef(null);\n  const [pos, setPos] = useState({ x: card.x, y: card.y });\n\n  const onMouseDown = (e) => {\n    e.stopPropagation();\n    dragStart.current = { mx: e.clientX, my: e.clientY, x: pos.x, y: pos.y };\n    const onMove = (ev) => {\n      const nx = dragStart.current.x + (ev.clientX - dragStart.current.mx);\n      const ny = dragStart.current.y + (ev.clientY - dragStart.current.my);\n      setPos({ x: nx, y: ny });\n      moveCard(canvasId, card.id, nx, ny);\n    };\n    const onUp = () => {\n      window.removeEventListener('mousemove', onMove);\n      window.removeEventListener('mouseup', onUp);\n    };\n    window.addEventListener('mousemove', onMove);\n    window.addEventListener('mouseup', onUp);\n  };\n\n  return (\n    <div\n      onMouseDown={onMouseDown}\n      style={{\n        position: 'absolute',\n        left: pos.x,\n        top: pos.y,\n        width: 160,\n        background: '#fff',\n        borderRadius: 12,\n        boxShadow: '0 4px 24px rgba(124,58,237,.25)',\n        border: '2px solid #fbbf24',\n        cursor: 'grab',\n        zIndex: 10,\n        userSelect: 'none',\n        overflow: 'hidden',\n        transition: 'box-shadow .15s',\n      }}\n    >\n      <img\n        src={card.product.img}\n        alt={card.product.name}\n        style={{ width: '100%', height: 110, objectFit: 'cover', display: 'block', pointerEvents: 'none' }}\n        onError={e => { e.target.style.background = '#f4f0ff'; e.target.style.display = 'none'; }}\n      />\n      <div style={{ padding: '8px 10px 8px' }}>\n        <div style={{ fontSize: '.75rem', fontWeight: 800, color: '#1a0a3e', marginBottom: 2, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>\n          {card.product.name}\n        </div>\n        <div style={{ fontSize: '.82rem', fontWeight: 800, color: '#fbbf24', marginBottom: 6 }}>\n          {card.product.price}\n        </div>\n        <div style={{ display: 'flex', gap: 4 }}>\n          <button\n            onClick={() => safeOpen(card.product.url)}\n            style={{ flex: 1, background: 'linear-gradient(90deg,#7c3aed,#5b21b6)', color: '#fff', border: '1.5px solid #fbbf24', borderRadius: 6, padding: '5px 0', fontSize: '.65rem', fontWeight: 700, cursor: 'pointer' }}\n          >\n            Add to Cart\n          </button>\n          {isOwner && (\n            <button\n              onClick={() => removeCard(canvasId, card.id, userId)}\n              style={{ background: '#fee2e2', color: '#b91c1c', border: '1px solid #fca5a5', borderRadius: 6, padding: '5px 8px', fontSize: '.65rem', fontWeight: 700, cursor: 'pointer' }}\n            >\n              ✕\n            </button>\n          )}\n        </div>\n      </div>\n    </div>\n  );\n}\n"
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\ProductCard.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/ProductCard.jsx")

# src/components/EmojiSticker.jsx
content = "import { useState, useRef } from 'react';\nimport { useCanvasStore } from '../store/canvas';\nimport { useAuthStore } from '../store/auth';\n\nexport default function EmojiSticker({ sticker, canvasId }) {\n  const moveSticker   = useCanvasStore(s => s.moveSticker);\n  const removeSticker = useCanvasStore(s => s.removeSticker);\n  const user          = useAuthStore(s => s.user);\n  const userId        = user?.id || '';\n  const isOwner       = sticker.ownerId === userId || sticker.ownerId?.startsWith('guest');\n\n  const [pos, setPos]       = useState({ x: sticker.x, y: sticker.y });\n  const [showDel, setShowDel] = useState(false);\n  const dragStart = useRef(null);\n\n  const onMouseDown = (e) => {\n    e.stopPropagation();\n    dragStart.current = { mx: e.clientX, my: e.clientY, x: pos.x, y: pos.y };\n    const onMove = (ev) => {\n      const nx = dragStart.current.x + (ev.clientX - dragStart.current.mx);\n      const ny = dragStart.current.y + (ev.clientY - dragStart.current.my);\n      setPos({ x: nx, y: ny });\n      moveSticker(canvasId, sticker.id, nx, ny);\n    };\n    const onUp = () => {\n      window.removeEventListener('mousemove', onMove);\n      window.removeEventListener('mouseup', onUp);\n    };\n    window.addEventListener('mousemove', onMove);\n    window.addEventListener('mouseup', onUp);\n  };\n\n  return (\n    <div\n      onMouseDown={onMouseDown}\n      onDoubleClick={() => isOwner && setShowDel(v => !v)}\n      style={{ position: 'absolute', left: pos.x, top: pos.y, cursor: 'grab', zIndex: 11, userSelect: 'none', fontSize: 32, lineHeight: 1 }}\n      title={isOwner ? 'Double-click to delete' : 'Move me!'}\n    >\n      {sticker.emoji}\n      {showDel && isOwner && (\n        <button\n          onClick={() => removeSticker(canvasId, sticker.id, userId)}\n          style={{ position: 'absolute', top: -8, right: -8, background: '#ef4444', color: '#fff', border: 'none', borderRadius: '50%', width: 18, height: 18, fontSize: 10, cursor: 'pointer', fontWeight: 800, lineHeight: '18px', padding: 0 }}\n        >✕</button>\n      )}\n    </div>\n  );\n}\n"
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\EmojiSticker.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/EmojiSticker.jsx")

# src/components/CanvasOverlayLayer.jsx
content = "import { useCanvasStore } from '../store/canvas';\nimport ProductCard from './ProductCard';\nimport EmojiSticker from './EmojiSticker';\n\nexport default function CanvasOverlayLayer({ canvasId }) {\n  const cards    = useCanvasStore(s => s.cards[canvasId]    || []);\n  const stickers = useCanvasStore(s => s.stickers[canvasId] || []);\n\n  return (\n    <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none', zIndex: 5 }}>\n      <div style={{ position: 'relative', width: '100%', height: '100%', pointerEvents: 'auto' }}>\n        {cards.map(card => (\n          <ProductCard key={card.id} card={card} canvasId={canvasId} />\n        ))}\n        {stickers.map(sticker => (\n          <EmojiSticker key={sticker.id} sticker={sticker} canvasId={canvasId} />\n        ))}\n      </div>\n    </div>\n  );\n}\n"
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\CanvasOverlayLayer.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/CanvasOverlayLayer.jsx")

# src/components/VoiceRecorder.jsx
content = 'import { useState, useRef } from \'react\';\nimport { useCanvasStore } from \'../store/canvas\';\n\nexport default function VoiceRecorder({ canvasId, onAudioReady, userName = \'You\' }) {\n  const [recording, setRecording] = useState(false);\n  const [duration,  setDuration]  = useState(0);\n  const mediaRef  = useRef(null);\n  const chunksRef = useRef([]);\n  const timerRef  = useRef(null);\n  const setRec    = useCanvasStore(s => s.setRecording);\n  const clearRec  = useCanvasStore(s => s.clearRecording);\n\n  const startRecording = async (e) => {\n    e.preventDefault();\n    try {\n      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });\n      const mr = new MediaRecorder(stream);\n      mediaRef.current = mr;\n      chunksRef.current = [];\n      mr.ondataavailable = ev => { if (ev.data.size > 0) chunksRef.current.push(ev.data); };\n      mr.onstop = () => {\n        const blob = new Blob(chunksRef.current, { type: \'audio/webm\' });\n        const url  = URL.createObjectURL(blob);\n        stream.getTracks().forEach(t => t.stop());\n        clearRec(canvasId);\n        onAudioReady(url, duration || 1);\n        setDuration(0);\n      };\n      mr.start();\n      setRecording(true);\n      setRec(canvasId, { userId: \'me\', userName });\n      let secs = 0;\n      timerRef.current = setInterval(() => { secs++; setDuration(secs); }, 1000);\n    } catch {\n      alert(\'Microphone access denied. Please allow microphone to send voice messages.\');\n    }\n  };\n\n  const stopRecording = (e) => {\n    e.preventDefault();\n    if (mediaRef.current && recording) {\n      clearInterval(timerRef.current);\n      mediaRef.current.stop();\n      setRecording(false);\n    }\n  };\n\n  return (\n    <div style={{ display: \'flex\', alignItems: \'center\', gap: 8, padding: \'4px 0\' }}>\n      <button\n        onMouseDown={startRecording}\n        onMouseUp={stopRecording}\n        onTouchStart={startRecording}\n        onTouchEnd={stopRecording}\n        style={{\n          width: 36, height: 36, borderRadius: \'50%\',\n          background: recording\n            ? \'linear-gradient(90deg,#ef4444,#dc2626)\'\n            : \'linear-gradient(90deg,#7c3aed,#5b21b6)\',\n          border: \'1.5px solid #fbbf24\',\n          color: \'#fff\', cursor: \'pointer\',\n          display: \'flex\', alignItems: \'center\', justifyContent: \'center\',\n          flexShrink: 0,\n          animation: recording ? \'lp 1s infinite\' : \'none\',\n        }}\n        title="Hold to record voice message"\n      >\n        <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">\n          <path d="M12 2a3 3 0 0 1 3 3v6a3 3 0 0 1-6 0V5a3 3 0 0 1 3-3zm-1 14.93V20H9v2h6v-2h-2v-3.07A7 7 0 0 0 19 11h-2a5 5 0 0 1-10 0H5a7 7 0 0 0 6 6.93z"/>\n        </svg>\n      </button>\n      {recording ? (\n        <div style={{ display: \'flex\', alignItems: \'center\', gap: 6 }}>\n          <div style={{ width: 8, height: 8, borderRadius: \'50%\', background: \'#ef4444\' }}/>\n          <span style={{ fontSize: \'.72rem\', color: \'#ef4444\', fontWeight: 700 }}>\n            Recording... {duration}s\n          </span>\n          <span style={{ fontSize: \'.65rem\', color: \'rgba(255,255,255,.4)\' }}>Release to send</span>\n        </div>\n      ) : (\n        <span style={{ fontSize: \'.68rem\', color: \'rgba(255,255,255,.4)\' }}>\n          Hold to record voice note\n        </span>\n      )}\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\VoiceRecorder.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/VoiceRecorder.jsx")

# src/components/AudioMessage.jsx
content = 'import { useState, useRef, useEffect } from \'react\';\n\nexport default function AudioMessage({ url, duration, sender, time, isMe }) {\n  const [playing,  setPlaying]  = useState(false);\n  const [progress, setProgress] = useState(0);\n  const audioRef = useRef(null);\n\n  useEffect(() => {\n    const audio = audioRef.current;\n    if (!audio) return;\n    const onTime = () => setProgress((audio.currentTime / (audio.duration || 1)) * 100);\n    const onEnd  = () => { setPlaying(false); setProgress(0); };\n    audio.addEventListener(\'timeupdate\', onTime);\n    audio.addEventListener(\'ended\', onEnd);\n    return () => {\n      audio.removeEventListener(\'timeupdate\', onTime);\n      audio.removeEventListener(\'ended\', onEnd);\n    };\n  }, []);\n\n  const toggle = () => {\n    const audio = audioRef.current;\n    if (!audio) return;\n    if (playing) { audio.pause(); setPlaying(false); }\n    else { audio.play(); setPlaying(true); }\n  };\n\n  // Generate pseudo-waveform bars from the url string as a seed\n  const bars = Array.from({ length: 20 }, (_, i) => {\n    const seed = (url.charCodeAt(i % url.length) || 50);\n    return 8 + (seed % 20);\n  });\n\n  return (\n    <div style={{\n      background: isMe ? \'linear-gradient(90deg,#7c3aed,#5b21b6)\' : \'rgba(255,255,255,.1)\',\n      borderRadius: 12, padding: \'8px 12px\', maxWidth: 240,\n      border: \'1px solid rgba(251,191,36,.35)\',\n    }}>\n      <audio ref={audioRef} src={url} preload="metadata"/>\n      <div style={{ display: \'flex\', alignItems: \'center\', gap: 8 }}>\n        <button\n          onClick={toggle}\n          style={{\n            width: 34, height: 34, borderRadius: \'50%\',\n            background: \'rgba(255,255,255,.2)\', border: \'1.5px solid #fbbf24\',\n            color: \'#fff\', cursor: \'pointer\',\n            display: \'flex\', alignItems: \'center\', justifyContent: \'center\', flexShrink: 0,\n          }}\n        >\n          {playing\n            ? <svg width="10" height="10" viewBox="0 0 24 24" fill="currentColor"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>\n            : <svg width="10" height="10" viewBox="0 0 24 24" fill="currentColor"><polygon points="5,3 19,12 5,21"/></svg>\n          }\n        </button>\n        {/* Waveform */}\n        <div style={{ flex: 1, display: \'flex\', alignItems: \'center\', gap: 2, height: 28 }}>\n          {bars.map((h, i) => (\n            <div key={i} style={{\n              width: 3, borderRadius: 2,\n              height: h,\n              background: (i / 20) * 100 <= progress ? \'#fbbf24\' : \'rgba(255,255,255,.3)\',\n              transition: \'background .1s\',\n              flexShrink: 0,\n            }}/>\n          ))}\n        </div>\n        <span style={{ fontSize: \'.62rem\', color: \'rgba(255,255,255,.6)\', flexShrink: 0 }}>\n          {duration}s\n        </span>\n      </div>\n      <div style={{ fontSize: \'.6rem\', color: \'rgba(255,255,255,.4)\', marginTop: 4, textAlign: isMe ? \'right\' : \'left\' }}>\n        {sender}{time ? \' · \' + time : \'\'}\n      </div>\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\AudioMessage.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/AudioMessage.jsx")

# src/components/RecordingIndicator.jsx
content = "import { useCanvasStore } from '../store/canvas';\n\nexport default function RecordingIndicator({ canvasId }) {\n  const rec = useCanvasStore(s => s.recording[canvasId]);\n  if (!rec) return null;\n\n  return (\n    <div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '4px 10px', fontSize: '.72rem', color: 'rgba(255,255,255,.7)', borderTop: '1px solid rgba(255,255,255,.08)' }}>\n      <div style={{ display: 'flex', gap: 2, alignItems: 'flex-end' }}>\n        {[8, 14, 10].map((h, i) => (\n          <div key={i} style={{\n            width: 3, height: h, borderRadius: 2, background: '#ef4444',\n            animation: `bounce ${0.4 + i * 0.1}s ease infinite alternate`,\n          }}/>\n        ))}\n      </div>\n      <span><strong style={{ color: '#fbbf24' }}>{rec.userName}</strong> is recording a voice message...</span>\n      <style>{`@keyframes bounce { from{transform:scaleY(.4)} to{transform:scaleY(1)} }`}</style>\n    </div>\n  );\n}\n"
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\RecordingIndicator.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/RecordingIndicator.jsx")

# src/components/CanvasChatPanel.jsx
content = 'import { useState, useRef, useEffect } from \'react\';\nimport VoiceRecorder from \'./VoiceRecorder\';\nimport AudioMessage from \'./AudioMessage\';\nimport RecordingIndicator from \'./RecordingIndicator\';\n\nconst EMOJI_LIST = [\'😀\',\'❤️\',\'👍\',\'🔥\',\'😍\',\'🎉\',\'💯\',\'😂\',\'👏\',\'🙏\',\'💪\',\'✨\',\'🛒\',\'⭐\',\'🤩\',\'💅\'];\n\nexport default function CanvasChatPanel({ canvasId, initialMessages = [], style = {} }) {\n  const [msgs, setMsgs]           = useState(initialMessages);\n  const [text, setText]           = useState(\'\');\n  const [showEmoji, setShowEmoji] = useState(false);\n  const bottomRef = useRef(null);\n\n  useEffect(() => {\n    bottomRef.current?.scrollIntoView({ behavior: \'smooth\' });\n  }, [msgs]);\n\n  const now = () => {\n    const d = new Date();\n    return d.getHours() + \':\' + String(d.getMinutes()).padStart(2, \'0\');\n  };\n\n  const sendText = () => {\n    if (!text.trim()) return;\n    setMsgs(m => [...m, { id: Date.now(), type: \'text\', text, sender: \'You\', time: now(), isMe: true }]);\n    setText(\'\');\n    setShowEmoji(false);\n  };\n\n  const sendEmoji = (e) => {\n    setMsgs(m => [...m, { id: Date.now(), type: \'text\', text: e, sender: \'You\', time: now(), isMe: true }]);\n    setShowEmoji(false);\n  };\n\n  const onAudioReady = (url, duration) => {\n    setMsgs(m => [...m, { id: Date.now(), type: \'audio\', url, duration, sender: \'You\', time: now(), isMe: true }]);\n  };\n\n  return (\n    <div style={{ display: \'flex\', flexDirection: \'column\', height: \'100%\', background: \'linear-gradient(135deg,#1e1b4b,#4c1d95)\', borderRadius: 16, overflow: \'hidden\', ...style }}>\n      {/* Header */}\n      <div style={{ padding: \'10px 14px\', borderBottom: \'1px solid rgba(255,255,255,.1)\', display: \'flex\', alignItems: \'center\', gap: 6, flexShrink: 0 }}>\n        <div style={{ width: 8, height: 8, borderRadius: \'50%\', background: \'#22c55e\' }}/>\n        <span style={{ color: \'#fff\', fontWeight: 800, fontSize: \'.88rem\', flex: 1 }}>Canvas Chat</span>\n        <span style={{ fontSize: \'.68rem\', color: \'rgba(255,255,255,.4)\' }}>{msgs.length} messages</span>\n      </div>\n\n      {/* Messages */}\n      <div style={{ flex: 1, overflowY: \'auto\', padding: \'10px 12px\', display: \'flex\', flexDirection: \'column\', gap: 8 }}>\n        {msgs.map(m => (\n          <div key={m.id} style={{ display: \'flex\', flexDirection: m.isMe ? \'row-reverse\' : \'row\', gap: 6, alignItems: \'flex-end\' }}>\n            <div style={{ width: 28, height: 28, borderRadius: \'50%\', background: m.isMe ? \'#7c3aed\' : \'#5b21b6\', color: \'#fff\', fontSize: \'.7rem\', fontWeight: 800, display: \'flex\', alignItems: \'center\', justifyContent: \'center\', flexShrink: 0 }}>\n              {m.sender[0]}\n            </div>\n            {m.type === \'audio\'\n              ? <AudioMessage url={m.url} duration={m.duration} sender={m.sender} time={m.time} isMe={m.isMe}/>\n              : (\n                <div style={{ background: m.isMe ? \'linear-gradient(90deg,#7c3aed,#5b21b6)\' : \'rgba(255,255,255,.12)\', borderRadius: 12, padding: \'6px 10px\', maxWidth: \'75%\', border: \'1px solid rgba(251,191,36,.2)\' }}>\n                  {!m.isMe && <div style={{ fontSize: \'.65rem\', fontWeight: 700, color: \'rgba(255,255,255,.5)\', marginBottom: 2 }}>{m.sender}</div>}\n                  <div style={{ fontSize: \'.85rem\', color: \'#fff\', lineHeight: 1.4 }}>{m.text}</div>\n                  <div style={{ fontSize: \'.6rem\', color: \'rgba(255,255,255,.4)\', marginTop: 2, textAlign: m.isMe ? \'right\' : \'left\' }}>{m.time}</div>\n                </div>\n              )\n            }\n          </div>\n        ))}\n        <div ref={bottomRef}/>\n      </div>\n\n      {/* Recording indicator */}\n      <RecordingIndicator canvasId={canvasId}/>\n\n      {/* Input area */}\n      <div style={{ padding: \'8px 10px\', borderTop: \'1px solid rgba(255,255,255,.1)\', flexShrink: 0 }}>\n        {/* Text + emoji row */}\n        <div style={{ display: \'flex\', gap: 6, marginBottom: 6, position: \'relative\' }}>\n          <button\n            onClick={() => setShowEmoji(v => !v)}\n            style={{ background: \'rgba(255,255,255,.1)\', border: \'1.5px solid #fbbf24\', borderRadius: 8, width: 34, height: 34, cursor: \'pointer\', fontSize: 16, flexShrink: 0 }}\n          >😊</button>\n          {showEmoji && (\n            <div style={{ position: \'absolute\', bottom: \'110%\', left: 0, background: \'#fff\', borderRadius: 12, padding: 8, display: \'flex\', flexWrap: \'wrap\', gap: 4, width: 220, boxShadow: \'0 4px 20px rgba(0,0,0,.2)\', zIndex: 50, border: \'1.5px solid #fbbf24\' }}>\n              {EMOJI_LIST.map(e => (\n                <button key={e} onClick={() => sendEmoji(e)} style={{ fontSize: 20, background: \'none\', border: \'none\', cursor: \'pointer\', padding: 4, borderRadius: 6 }}>{e}</button>\n              ))}\n            </div>\n          )}\n          <input\n            value={text}\n            onChange={e => setText(e.target.value)}\n            onKeyDown={e => e.key === \'Enter\' && sendText()}\n            placeholder="Say something..."\n            style={{ flex: 1, background: \'rgba(255,255,255,.1)\', border: \'1px solid rgba(255,255,255,.15)\', borderRadius: 10, padding: \'6px 10px\', color: \'#fff\', fontSize: \'.82rem\', outline: \'none\' }}\n          />\n          <button\n            onClick={sendText}\n            style={{ background: \'linear-gradient(90deg,#7c3aed,#5b21b6)\', border: \'1.5px solid #fbbf24\', borderRadius: 10, width: 34, height: 34, color: \'#fff\', cursor: \'pointer\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', flexShrink: 0 }}\n          >\n            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>\n          </button>\n        </div>\n        {/* Voice row */}\n        <VoiceRecorder canvasId={canvasId} onAudioReady={onAudioReady} userName="You"/>\n      </div>\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\CanvasChatPanel.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/CanvasChatPanel.jsx")

# src/components/CollabCanvas.jsx
content = 'import { useState, useRef, useEffect } from \'react\';\nimport { useProductDrop } from \'../hooks/useProductDrop\';\nimport { useCanvasStore } from \'../store/canvas\';\nimport { useAuthStore } from \'../store/auth\';\nimport CanvasOverlayLayer from \'./CanvasOverlayLayer\';\nimport CanvasChatPanel from \'./CanvasChatPanel\';\nimport { CHAT_MSGS } from \'../data\';\n\nconst EMOJIS = [\'😀\',\'😂\',\'🥰\',\'😍\',\'🤩\',\'😎\',\'🥳\',\'🎉\',\'🔥\',\'💯\',\'👏\',\'✨\',\'💜\',\'💛\',\'🩵\',\'🛍️\',\'🎨\',\'👟\',\'👗\',\'💄\',\'⌚\',\'📱\',\'💻\',\'🎮\',\'🏠\',\'🍕\',\'🛒\',\'💪\',\'🧸\',\'📚\'];\n\nexport default function CollabCanvas() {\n  const canvasRef = useRef(null);\n  const [tool, setTool] = useState(\'draw\');\n  const [color, setColor] = useState(\'#7c3aed\');\n  const [size, setSize] = useState(\'md\');\n  const [msgs, setMsgs] = useState(CHAT_MSGS);\n  const [chatInput, setChatInput] = useState(\'\');\n  const [emojiOpen, setEmojiOpen] = useState(false);\n  const [activeTab, setActiveTab] = useState(\'chat\');\n  const [drawing, setDrawing] = useState(false);\n  const lastPos = useRef(null);\n  const msgsRef = useRef(null);\n\n  const colors = [\'#7c3aed\',\'#fbbf24\',\'#67e8f9\',\'#ef4444\',\'#22c55e\',\'#f97316\',\'#000000\',\'#ffffff\'];\n  const sizes = { sm: 2, md: 4, lg: 8 };\n\n  useEffect(() => {\n\n  // Product drop + overlay\n  const canvasContainerRef = useRef(null);\n  const { onDragOver, onDrop } = useProductDrop(\'main-collab\', canvasContainerRef);\n  const addSticker = useCanvasStore(s => s.addSticker);\n  const user = useAuthStore(s => s.user);\n  const [showStickerPicker, setShowStickerPicker] = useState(false);\n  const STICKER_EMOJIS = [\'🔥\',\'❤️\',\'👍\',\'😍\',\'💯\',\'⭐\',\'🛒\',\'💰\',\'✅\',\'🎉\',\'🤩\',\'💅\'];\n  const dropSticker = (emoji) => {\n    addSticker(\'main-collab\', {\n      id: Date.now().toString(),\n      emoji,\n      x: 80 + Math.random() * 300,\n      y: 60 + Math.random() * 200,\n      ownerId: user?.id || \'guest\',\n    });\n    setShowStickerPicker(false);\n  };\n    if (msgsRef.current) msgsRef.current.scrollTop = msgsRef.current.scrollHeight;\n  }, [msgs]);\n\n  const getPos = (e, canvas) => {\n    const r = canvas.getBoundingClientRect();\n    const scaleX = canvas.width / r.width;\n    const scaleY = canvas.height / r.height;\n    const src = e.touches ? e.touches[0] : e;\n    return { x: (src.clientX - r.left) * scaleX, y: (src.clientY - r.top) * scaleY };\n  };\n\n  const startDraw = e => {\n    const canvas = canvasRef.current;\n    if (!canvas) return;\n    e.preventDefault();\n    setDrawing(true);\n    lastPos.current = getPos(e, canvas);\n  };\n\n  const doDraw = e => {\n    if (!drawing) return;\n    const canvas = canvasRef.current;\n    const ctx = canvas.getContext(\'2d\');\n    const pos = getPos(e, canvas);\n    ctx.beginPath();\n    if (tool === \'erase\') {\n      ctx.globalCompositeOperation = \'destination-out\';\n      ctx.lineWidth = 24;\n    } else {\n      ctx.globalCompositeOperation = \'source-over\';\n      ctx.strokeStyle = color;\n      ctx.lineWidth = sizes[size];\n    }\n    ctx.lineCap = \'round\';\n    ctx.lineJoin = \'round\';\n    ctx.moveTo(lastPos.current.x, lastPos.current.y);\n    ctx.lineTo(pos.x, pos.y);\n    ctx.stroke();\n    lastPos.current = pos;\n  };\n\n  const endDraw = () => setDrawing(false);\n\n  const clearCanvas = () => {\n    const canvas = canvasRef.current;\n    if (canvas) canvas.getContext(\'2d\').clearRect(0, 0, canvas.width, canvas.height);\n  };\n\n  const sendMsg = () => {\n    if (!chatInput.trim()) return;\n    setMsgs(m => [...m, { name: \'You\', me: true, text: chatInput.trim(), time: new Date().toLocaleTimeString(\'en\',{hour:\'2-digit\',minute:\'2-digit\'}) }]);\n    setChatInput(\'\');\n  };\n\n  return (\n    <div id="collabSection" style={{\n      background: \'linear-gradient(135deg,#3b0764,#5b21b6)\',\n      padding: \'1.2rem 2rem 1.5rem\',\n      position: \'relative\',\n      overflow: \'hidden\',\n    }}>\n      <style>{`\n        @keyframes invpulse { 0%,100%{box-shadow:0 4px 20px rgba(249,115,22,.45)} 50%{box-shadow:0 6px 32px rgba(249,115,22,.8),0 0 0 8px rgba(249,115,22,.1)} }\n        @keyframes pulseLive2 { 0%,100%{opacity:1} 50%{opacity:.75} }\n        @keyframes tdot { 0%,60%,100%{transform:translateY(0)} 30%{transform:translateY(-4px)} }\n        @keyframes wwave { 0%,100%{transform:scaleY(1)} 50%{transform:scaleY(1.6)} }\n        @keyframes blinkdot { 0%,100%{opacity:1} 50%{opacity:.2} }\n        .collab-orb { position:absolute; top:-60px; right:-60px; width:260px; height:260px; border-radius:50%; background:radial-gradient(circle,rgba(103,232,249,.08),transparent 70%); pointer-events:none; }\n        .collab-inner { max-width:1200px; margin:0 auto; }\n        .collab-head { display:flex; flex-direction:row; align-items:center; justify-content:space-between; gap:1rem; flex-wrap:wrap; margin-bottom:.6rem; }\n        .invite-btn {\n          background:linear-gradient(135deg,#f59e0b,#f97316); color:#fff; border:none;\n          border-radius:10px; padding:8px 20px; font-family:\'Space Grotesk\',sans-serif;\n          font-size:13px; font-weight:800; cursor:pointer; animation:invpulse 2.5s infinite;\n          white-space:nowrap;\n        }\n        .invite-btn:hover { transform:translateY(-2px) scale(1.03); }\n        .live-count-badge {\n          background:rgba(34,197,94,.2); border:1px solid rgba(34,197,94,.4); color:#4ade80;\n          font-size:10px; font-weight:800; padding:2px 8px; border-radius:20px;\n          display:inline-flex; align-items:center; gap:4px;\n        }\n        .live-dot { width:6px; height:6px; border-radius:50%; background:#22c55e; animation:pulseLive2 1.5s infinite; display:inline-block; }\n        .collab-grid { display:grid; grid-template-columns:1fr 305px; gap:14px; }\n        .cv-panel { border:2px solid rgba(251,191,36,.4); border-radius:16px; overflow:hidden; display:flex; flex-direction:column; }\n        .cv-top { background:rgba(0,0,0,.3); padding:8px 12px; display:flex; align-items:center; gap:8px; }\n        .cv-tools { background:rgba(0,0,0,.25); padding:7px 10px; display:flex; align-items:center; gap:6px; flex-wrap:wrap; }\n        .t-chip {\n          background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.15);\n          color:rgba(255,255,255,.8); border-radius:7px; padding:5px 10px; font-size:11px;\n          font-weight:700; cursor:pointer; font-family:inherit; transition:.1s;\n        }\n        .t-chip.on,.t-chip:hover { background:rgba(251,191,36,.22); border-color:#fbbf24; color:#fbbf24; }\n        .cv-area { background:#fff; min-height:480px; position:relative; flex:1; }\n        .cv-area canvas { position:absolute; inset:0; width:100%; height:100%; }\n        .cv-hint { position:absolute; inset:0; display:flex; align-items:center; justify-content:center; pointer-events:none; transition:opacity .4s; }\n        .chat-panel { background:rgba(0,0,0,.28); border-radius:16px; display:flex; flex-direction:column; overflow:hidden; border:1px solid rgba(255,255,255,.08); }\n        .ctabs { display:flex; border-bottom:1px solid rgba(255,255,255,.08); }\n        .ctab { flex:1; padding:.55rem; text-align:center; font-size:.72rem; font-weight:800; color:rgba(255,255,255,.4); cursor:pointer; border-bottom:2px solid transparent; transition:.15s; background:none; border-top:none; border-left:none; border-right:none; font-family:inherit; }\n        .ctab.on { color:#67e8f9; border-bottom-color:#67e8f9; }\n        .who-bar { padding:.4rem .75rem; border-bottom:1px solid rgba(255,255,255,.08); display:flex; gap:.35rem; align-items:center; flex-wrap:wrap; }\n        .who-pill { display:flex; align-items:center; gap:.22rem; background:rgba(255,255,255,.07); border:1px solid rgba(255,255,255,.1); border-radius:999px; padding:2px 7px; font-size:.65rem; color:rgba(255,255,255,.75); font-weight:600; }\n        .msgs { flex:1; overflow-y:auto; padding:.6rem; display:flex; flex-direction:column; gap:.45rem; max-height:380px; scrollbar-width:thin; scrollbar-color:rgba(255,255,255,.1) transparent; }\n        .mw { display:flex; flex-direction:column; max-width:90%; }\n        .mw.me { align-self:flex-end; align-items:flex-end; }\n        .mw.them { align-self:flex-start; align-items:flex-start; }\n        .mname { font-size:.58rem; color:rgba(255,255,255,.4); margin-bottom:2px; font-weight:700; text-transform:uppercase; }\n        .mbbl { padding:.4rem .65rem; border-radius:10px; font-size:.75rem; line-height:1.45; }\n        .mw.me .mbbl { background:rgba(251,191,36,.2); color:#fde68a; border-bottom-right-radius:3px; }\n        .mw.them .mbbl { background:rgba(103,232,249,.15); color:#a5f3fc; border-bottom-left-radius:3px; }\n        .mtime { font-size:.58rem; color:rgba(255,255,255,.25); margin-top:2px; }\n        .chat-inp { border-top:1px solid rgba(255,255,255,.08); padding:.55rem; display:flex; flex-direction:column; gap:.35rem; }\n        .cinp-row { display:flex; gap:.4rem; align-items:flex-end; }\n        .cinp { flex:1; background:rgba(255,255,255,.08); border:1px solid rgba(255,255,255,.12); border-radius:9px; padding:.42rem .65rem; color:#fff; font-size:.75rem; resize:none; outline:none; font-family:inherit; max-height:65px; }\n        .cinp::placeholder { color:rgba(255,255,255,.35); }\n        .cinp:focus { border-color:rgba(103,232,249,.4); }\n        .sbtn { background:#fbbf24; color:#3b0764; border:none; border-radius:8px; width:32px; height:32px; display:flex; align-items:center; justify-content:center; cursor:pointer; font-size:.85rem; font-weight:800; flex-shrink:0; }\n        .emoji-btn { background:rgba(255,255,255,.15); border:1.5px solid rgba(255,255,255,.3); border-radius:8px; padding:5px 10px; font-size:18px; cursor:pointer; transition:.15s; flex-shrink:0; }\n        .emoji-picker { position:absolute; bottom:100%; left:0; background:#fff; border:1.5px solid #ede9fe; border-radius:14px; padding:.7rem; box-shadow:0 8px 40px rgba(124,58,237,.25); z-index:9998; width:260px; max-height:200px; overflow-y:auto; }\n        .emoji-grid { display:grid; grid-template-columns:repeat(8,1fr); gap:2px; }\n        .ep-em { font-size:20px; cursor:pointer; padding:5px; border-radius:8px; text-align:center; transition:.1s; display:flex; align-items:center; justify-content:center; }\n        .ep-em:hover { background:#f4f0ff; transform:scale(1.2); }\n        @media(max-width:900px) { .collab-grid { grid-template-columns:1fr; } }\n      `}</style>\n\n      <div className="collab-orb" />\n\n      <div className="collab-inner">\n        {/* Header */}\n        <div className="collab-head">\n          <div>\n            <h2 style={{ fontSize: \'1.1rem\', fontWeight: \'800\', color: \'#fff\', display: \'flex\', alignItems: \'center\', gap: \'8px\', margin: 0 }}>\n              🎨 Collaborative Canvas\n              <span className="live-count-badge"><span className="live-dot" /> 247 drawing now</span>\n            </h2>\n            <p style={{ fontSize: \'.7rem\', color: \'rgba(255,255,255,.5)\', margin: \'3px 0 0\' }}>Draw together, find products, shop as a team</p>\n          </div>\n          <button className="invite-btn">🔗 Invite Friends &amp; Family</button>\n        </div>\n\n        {/* Grid */}\n        <div className="collab-grid">\n          {/* Canvas Panel */}\n          <div className="cv-panel">\n            <div className="cv-top">\n              <span style={{ background: \'#ef4444\', color: \'#fff\', fontSize: \'10px\', fontWeight: \'800\', padding: \'3px 9px\', borderRadius: \'20px\', display: \'flex\', alignItems: \'center\', gap: \'4px\' }}>\n                <span style={{ width: \'5px\', height: \'5px\', borderRadius: \'50%\', background: \'#fff\', animation: \'blinkdot 1s infinite\', display: \'inline-block\' }} /> LIVE\n              </span>\n              <div style={{ display: \'flex\', gap: \'4px\' }}>\n                {[\'#7c3aed\',\'#fbbf24\',\'#67e8f9\',\'#ef4444\',\'#22c55e\',\'#000\'].map((c, i) => (\n                  <div key={i} onClick={() => { setColor(c); setTool(\'draw\'); }} style={{ width: \'16px\', height: \'16px\', borderRadius: \'50%\', background: c, cursor: \'pointer\', border: `2px solid ${color===c?\'#fff\':\'transparent\'}`, transition: \'.12s\' }} />\n                ))}\n              </div>\n              <div style={{ display: \'flex\', gap: \'3px\', marginLeft: \'4px\' }}>\n                {[\'sm\',\'md\',\'lg\'].map(s => (\n                  <div key={s} onClick={() => setSize(s)} style={{ background: size===s?\'rgba(251,191,36,.22)\':\'rgba(255,255,255,.1)\', border: `1px solid ${size===s?\'#fbbf24\':\'rgba(255,255,255,.15)\'}`, borderRadius: \'5px\', width: \'26px\', height: \'22px\', display: \'flex\', alignItems: \'center\', justifyContent: \'center\', cursor: \'pointer\' }}>\n                    <span style={{ background: \'#fff\', borderRadius: \'50%\', display: \'block\', width: s===\'sm\'?\'4px\':s===\'md\'?\'7px\':\'10px\', height: s===\'sm\'?\'4px\':s===\'md\'?\'7px\':\'10px\' }} />\n                  </div>\n                ))}\n              </div>\n              <span style={{ marginLeft: \'auto\', color: \'rgba(255,255,255,.65)\', fontSize: \'12px\', fontWeight: \'600\' }}>Room: #spring2026</span>\n            </div>\n\n            <div className="cv-tools">\n              {[[\'draw\',\'✏️ Draw\'],[\'erase\',\'🧹 Erase\']].map(([t,l]) => (\n                <button key={t} className={`t-chip ${tool===t?\'on\':\'\'}`} onClick={() => setTool(t)}>{l}</button>\n              ))}\n              <button className="t-chip" onClick={clearCanvas}>Clear</button>\n              <div style={{ position: \'relative\' }}>\n                <button\n                  onClick={() => setShowStickerPicker(v => !v)}\n                  style={{ background:\'rgba(255,255,255,.15)\', border:\'1.5px solid #fbbf24\', borderRadius:8, padding:\'4px 10px\', fontSize:\'.75rem\', fontWeight:700, cursor:\'pointer\', color:\'#fff\' }}\n                >+ Sticker</button>\n                {showStickerPicker && (\n                  <div style={{ position:\'absolute\', top:\'110%\', left:0, background:\'#fff\', borderRadius:12, padding:8, boxShadow:\'0 4px 20px rgba(0,0,0,.2)\', display:\'flex\', gap:4, flexWrap:\'wrap\', width:220, zIndex:50, border:\'1.5px solid #fbbf24\' }}>\n                    {STICKER_EMOJIS.map(e => (\n                      <button key={e} onClick={() => dropSticker(e)} style={{ fontSize:22, background:\'none\', border:\'none\', cursor:\'pointer\', padding:4, borderRadius:6 }}>{e}</button>\n                    ))}\n                  </div>\n                )}\n              </div>\n              <button className="t-chip" style={{ marginLeft: \'auto\' }}>💾 Save</button>\n              <button className="t-chip">📤 Share</button>\n            </div>\n\n            <div className="cv-area" style={{ cursor: tool===\'erase\'?\'cell\':\'crosshair\' }}>\n              <div\n                  ref={canvasContainerRef}\n                  style={{ position: \'relative\', flex: 1 }}\n                  onDragOver={onDragOver}\n                  onDrop={onDrop}\n                >\n                  <canvas\n                ref={canvasRef}\n                width={1000}\n                height={600}\n                style={{ position: \'absolute\', inset: 0, width: \'100%\', height: \'100%\' }}\n                onMouseDown={startDraw}\n                onMouseMove={doDraw}\n                onMouseUp={endDraw}\n                onMouseLeave={endDraw}\n                onTouchStart={startDraw}\n                onTouchMove={doDraw}\n                onTouchEnd={endDraw}\n              />\n                  <CanvasOverlayLayer canvasId="main-collab" />\n                </div>\n              <div className="cv-hint">\n                <span style={{ fontSize: \'13px\', color: \'rgba(124,58,237,.2)\', fontWeight: \'600\' }}>✏️ Draw or drag a product here — friends see it live!</span>\n              </div>\n            </div>\n          </div>\n\n          {/* Chat Panel */}\n          <div className="chat-panel">\n            <div className="ctabs">\n              {[[\'chat\',\'💬 Chat\'],[\'products\',\'🛍️ Products\'],[\'rooms\',\'🚪 Rooms\']].map(([t,l]) => (\n                <button key={t} className={`ctab ${activeTab===t?\'on\':\'\'}`} onClick={() => setActiveTab(t)}>{l}</button>\n              ))}\n            </div>\n\n            <div className="who-bar">\n              <span style={{ fontSize: \'.62rem\', color: \'rgba(255,255,255,.4)\', fontWeight: \'700\' }}>In room:</span>\n              {[\'Anna 🟢\',\'Maja 🟢\',\'You 🟢\'].map(n => (\n                <span key={n} className="who-pill"><span style={{ width: \'5px\', height: \'5px\', borderRadius: \'50%\', background: \'#22c55e\', display: \'inline-block\' }} />{n}</span>\n              ))}\n            </div>\n\n            <div className="msgs" ref={msgsRef}>\n              {msgs.map((m, i) => (\n                <div key={i} className={`mw ${m.me ? \'me\' : \'them\'}`}>\n                  {!m.me && <div className="mname">{m.name}</div>}\n                  <div className="mbbl">{m.text}</div>\n                  <div className="mtime">{m.time}</div>\n                </div>\n              ))}\n            </div>\n\n            <div className="chat-inp" style={{ position: \'relative\' }}>\n              {emojiOpen && (\n                <div className="emoji-picker">\n                  <div className="emoji-grid">\n                    {EMOJIS.map(em => (\n                      <div key={em} className="ep-em" onClick={() => { setChatInput(v => v + em); setEmojiOpen(false); }}>{em}</div>\n                    ))}\n                  </div>\n                </div>\n              )}\n              <div className="cinp-row">\n                <button className="emoji-btn" onClick={() => setEmojiOpen(o => !o)}>😊</button>\n                <textarea\n                  className="cinp"\n                  placeholder="Message Anna & Maja… 😊"\n                  value={chatInput}\n                  rows={1}\n                  onChange={e => setChatInput(e.target.value)}\n                  onKeyDown={e => { if (e.key === \'Enter\' && !e.shiftKey) { e.preventDefault(); sendMsg(); } }}\n                />\n                <button className="sbtn" onClick={sendMsg}>→</button>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\CollabCanvas.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/CollabCanvas.jsx")

# src/components/Hero.jsx
content = 'import { useState, useEffect, useRef } from \'react\';\nimport { HERO_ADS } from \'../data\';\n\nfunction MiniCanvas() {\n  const canvasRef = useRef(null);\n  const heroContainerRef = useRef(null);\n  const { onDragOver: heroDragOver, onDrop: heroDrop } = useProductDrop(\'hero-canvas\', heroContainerRef);\n  const [tool, setTool] = useState(\'draw\');\n  const [color, setColor] = useState(\'#7c3aed\');\n  const [drawing, setDrawing] = useState(false);\n  const [hasDrawing, setHasDrawing] = useState(false);\n  const lastPos = useRef(null);\n\n  const colors = [\'#7c3aed\', \'#fbbf24\', \'#67e8f9\', \'#ef4444\', \'#22c55e\', \'#000\'];\n\n  const getPos = (e, canvas) => {\n    const r = canvas.getBoundingClientRect();\n    const src = e.touches ? e.touches[0] : e;\n    return { x: src.clientX - r.left, y: src.clientY - r.top };\n  };\n\n  const startDraw = (e) => {\n    const canvas = canvasRef.current;\n    if (!canvas) return;\n    e.preventDefault();\n    setDrawing(true);\n    lastPos.current = getPos(e, canvas);\n  };\n\n  const doDraw = (e) => {\n    if (!drawing) return;\n    const canvas = canvasRef.current;\n    const ctx = canvas.getContext(\'2d\');\n    const pos = getPos(e, canvas);\n    ctx.beginPath();\n    if (tool === \'erase\') {\n      ctx.globalCompositeOperation = \'destination-out\';\n      ctx.lineWidth = 20;\n    } else {\n      ctx.globalCompositeOperation = \'source-over\';\n      ctx.strokeStyle = color;\n      ctx.lineWidth = 3;\n    }\n    ctx.lineCap = \'round\';\n    ctx.moveTo(lastPos.current.x, lastPos.current.y);\n    ctx.lineTo(pos.x, pos.y);\n    ctx.stroke();\n    lastPos.current = pos;\n    setHasDrawing(true);\n  };\n\n  const endDraw = () => setDrawing(false);\n\n  const clearCanvas = () => {\n    const canvas = canvasRef.current;\n    if (!canvas) return;\n    canvas.getContext(\'2d\').clearRect(0, 0, canvas.width, canvas.height);\n    setHasDrawing(false);\n  };\n\n  return (\n    <div style={{ background: \'rgba(255,255,255,.07)\', border: \'2px solid rgba(251,191,36,.3)\', borderRadius: \'18px\', overflow: \'hidden\' }}>\n      {/* Canvas top bar */}\n      <div style={{ background: \'rgba(0,0,0,.3)\', padding: \'8px 12px\', display: \'flex\', alignItems: \'center\', justifyContent: \'space-between\' }}>\n        <span style={{ background: \'#ef4444\', color: \'#fff\', fontSize: \'10px\', fontWeight: \'800\', padding: \'3px 9px\', borderRadius: \'20px\', display: \'flex\', alignItems: \'center\', gap: \'4px\' }}>\n          <span style={{ width: \'5px\', height: \'5px\', borderRadius: \'50%\', background: \'#fff\', animation: \'blink 1s infinite\', display: \'inline-block\' }} />\n          LIVE\n        </span>\n        <span style={{ color: \'rgba(255,255,255,.65)\', fontSize: \'12px\', fontWeight: \'600\' }}>Your Canvas</span>\n        <div style={{ display: \'flex\' }}>\n          {[\'A\',\'M\',\'J\'].map((l, i) => (\n            <div key={i} style={{\n              width: \'25px\', height: \'25px\', borderRadius: \'50%\', marginLeft: i > 0 ? \'-7px\' : 0,\n              border: \'2px solid rgba(255,255,255,.3)\', display: \'flex\', alignItems: \'center\',\n              justifyContent: \'center\', fontSize: \'10px\', fontWeight: \'800\', color: \'#fff\',\n              background: [\'#7c3aed\',\'#fbbf24\',\'#22c55e\'][i],\n            }}>{l}</div>\n          ))}\n        </div>\n      </div>\n\n      {/* Canvas */}\n      <div style={{ background: \'#fff\', height: \'190px\', position: \'relative\', cursor: tool === \'erase\' ? \'cell\' : \'crosshair\' }}>\n        <div\n          ref={heroContainerRef}\n          style={{ position: \'relative\', flex: 1 }}\n          onDragOver={heroDragOver}\n          onDrop={heroDrop}\n        >\n          <canvas\n          ref={canvasRef}\n          width={300}\n          height={190}\n          style={{ position: \'absolute\', inset: 0, width: \'100%\', height: \'100%\' }}\n          onMouseDown={startDraw}\n          onMouseMove={doDraw}\n          onMouseUp={endDraw}\n          onMouseLeave={endDraw}\n          onTouchStart={startDraw}\n          onTouchMove={doDraw}\n          onTouchEnd={endDraw}\n        />\n          <CanvasOverlayLayer canvasId="hero-canvas" />\n        </div>\n        {!hasDrawing && (\n          <div style={{ position: \'absolute\', inset: 0, display: \'flex\', alignItems: \'center\', justifyContent: \'center\', pointerEvents: \'none\' }}>\n            <span style={{ fontSize: \'12px\', color: \'rgba(124,58,237,.25)\', fontWeight: \'600\' }}>✏️ Click to draw!</span>\n          </div>\n        )}\n      </div>\n\n      {/* Toolbar */}\n      <div style={{ background: \'rgba(0,0,0,.22)\', padding: \'7px 10px\', display: \'flex\', alignItems: \'center\', gap: \'5px\', flexWrap: \'wrap\' }}>\n        {[[\'draw\',\'✏️ Draw\'],[\'erase\',\'🧹 Erase\']].map(([t, label]) => (\n          <button\n            key={t}\n            onClick={() => setTool(t)}\n            style={{\n              background: tool === t ? \'rgba(251,191,36,.22)\' : \'rgba(255,255,255,.1)\',\n              border: `1px solid ${tool === t ? \'#fbbf24\' : \'rgba(255,255,255,.15)\'}`,\n              color: tool === t ? \'#fbbf24\' : \'rgba(255,255,255,.8)\',\n              borderRadius: \'7px\', padding: \'4px 9px\', fontSize: \'11px\', fontWeight: \'700\',\n              cursor: \'pointer\', fontFamily: \'inherit\',\n            }}\n          >{label}</button>\n        ))}\n        <button\n          onClick={clearCanvas}\n          style={{ background: \'rgba(255,255,255,.1)\', border: \'1px solid rgba(255,255,255,.15)\', color: \'rgba(255,255,255,.8)\', borderRadius: \'7px\', padding: \'4px 9px\', fontSize: \'11px\', fontWeight: \'700\', cursor: \'pointer\', fontFamily: \'inherit\' }}\n        >🗑 Clear</button>\n        <div style={{ display: \'flex\', gap: \'4px\', marginLeft: \'auto\', alignItems: \'center\' }}>\n          {colors.map(c => (\n            <div\n              key={c}\n              onClick={() => { setColor(c); setTool(\'draw\'); }}\n              style={{\n                width: \'17px\', height: \'17px\', borderRadius: \'50%\', background: c, cursor: \'pointer\',\n                border: `2.5px solid ${color === c ? \'#fff\' : \'transparent\'}`,\n                transform: color === c ? \'scale(1.2)\' : \'none\', transition: \'.15s\',\n              }}\n            />\n          ))}\n        </div>\n      </div>\n    </div>\n  );\n}\n\nfunction HeroAdCard({ ad }) {\n  return (\n    <div\n      draggable\n      style={{\n        background: \'rgba(255,255,255,.09)\', border: \'1px solid rgba(255,255,255,.15)\',\n        borderRadius: \'12px\', overflow: \'hidden\', cursor: \'grab\', transition: \'.2s\',\n      }}\n      onMouseEnter={e => { e.currentTarget.style.borderColor = \'rgba(251,191,36,.5)\'; e.currentTarget.style.transform = \'translateY(-2px)\'; }}\n      onMouseLeave={e => { e.currentTarget.style.borderColor = \'rgba(255,255,255,.15)\'; e.currentTarget.style.transform = \'none\'; }}\n      onClick={() => window.open(ad.url, \'_blank\')}\n    >\n      <img src={ad.img} alt={ad.name} width="155" height="56" style={{ width: \'100%\', height: \'56px\', objectFit: \'cover\', display: \'block\' }} />\n      <div style={{ padding: \'.35rem .5rem\' }}>\n        <div style={{ fontSize: \'.67rem\', fontWeight: \'700\', color: \'#fff\', lineHeight: 1.3 }}>{ad.name}</div>\n        <div style={{ fontSize: \'.76rem\', fontWeight: \'800\', color: \'#fbbf24\' }}>{ad.price}</div>\n      </div>\n      <button\n        style={{\n          width: \'100%\', background: \'rgba(251,191,36,.18)\', border: \'1px solid rgba(251,191,36,.3)\',\n          color: \'#fbbf24\', padding: \'4px\', fontSize: \'.6rem\', fontWeight: \'800\',\n          cursor: \'pointer\', fontFamily: \'inherit\',\n        }}\n        onClick={e => { e.stopPropagation(); window.open(ad.url, \'_blank\'); }}\n      >Shop Now →</button>\n    </div>\n  );\n}\n\nexport default function Hero({ onShare }) {\n  const [lIdx, setLIdx] = useState(0);\n  const [rIdx, setRIdx] = useState(4);\n  const [cIdx, setCIdx] = useState(8);\n  const [tick, setTick] = useState(0);\n\n  useEffect(() => {\n    const interval = setInterval(() => {\n      setTick(t => {\n        const next = t + 1;\n        if (next >= 16) {\n          setLIdx(i => (i + 4) % HERO_ADS.length);\n          setRIdx(i => (i + 4) % HERO_ADS.length);\n          setCIdx(i => (i + 2) % HERO_ADS.length);\n          return 0;\n        }\n        return next;\n      });\n    }, 500);\n    return () => clearInterval(interval);\n  }, []);\n\n  const leftAds  = [0,1,2,3].map(i => HERO_ADS[(lIdx + i) % HERO_ADS.length]);\n  const rightAds = [0,1,2,3].map(i => HERO_ADS[(rIdx + i) % HERO_ADS.length]);\n  const centerAds= [0,1].map(i => HERO_ADS[(cIdx + i) % HERO_ADS.length]);\n\n  return (\n    <div style={{\n      background: \'linear-gradient(140deg,#3b0764 0%,#5b21b6 50%,#7c3aed 100%)\',\n      padding: \'1rem 2rem .85rem\',\n      position: \'relative\',\n      overflow: \'hidden\',\n    }}>\n      <style>{`\n        @keyframes blink { 0%,100%{opacity:1} 50%{opacity:.2} }\n        @keyframes orbFloat { 0%,100%{transform:translateY(0) scale(1)} 50%{transform:translateY(-18px) scale(1.04)} }\n        @keyframes heroTitleIn { from{opacity:0;transform:translateY(24px)} to{opacity:1;transform:none} }\n        .hero-orb { position:absolute; border-radius:50%; pointer-events:none; }\n        .ho1 { top:-80px; right:-40px; width:380px; height:380px; background:radial-gradient(circle,rgba(103,232,249,.12),transparent 70%); animation:orbFloat 8s ease-in-out infinite; }\n        .ho2 { bottom:-100px; left:15%; width:300px; height:300px; background:radial-gradient(circle,rgba(251,191,36,.08),transparent 70%); animation:orbFloat 10s ease-in-out infinite 2s; }\n        .ho3 { top:30%; left:40%; width:200px; height:200px; background:radial-gradient(circle,rgba(124,58,237,.15),transparent 70%); animation:orbFloat 7s ease-in-out infinite 4s; }\n        .hero-inner {\n          max-width:1500px; margin:0 auto;\n          display:grid;\n          grid-template-columns: 155px 1fr 140px 370px 155px;\n          gap:1.2rem;\n          align-items:start;\n          position:relative; z-index:1;\n        }\n        .hero-tag {\n          display:inline-flex; align-items:center; gap:6px;\n          background:rgba(103,232,249,.12); border:1px solid rgba(103,232,249,.3);\n          color:#67e8f9; padding:5px 14px; border-radius:20px; font-size:11px;\n          font-weight:700; letter-spacing:.06em; margin-bottom:.4rem;\n        }\n        .hero h1 {\n          font-size:clamp(1.9rem,3.2vw,3rem); font-weight:800; color:#fff;\n          line-height:1.1; letter-spacing:-1.5px; margin-bottom:.6rem;\n          animation:heroTitleIn .8s cubic-bezier(.34,1.56,.64,1) both;\n        }\n        .hc { color:#67e8f9; } .hg { color:#fbbf24; }\n        .hero-sub {\n          color:rgba(255,255,255,.72); font-size:14px; line-height:1.6;\n          max-width:480px; margin-bottom:.8rem;\n          animation:heroTitleIn .8s .15s cubic-bezier(.34,1.56,.64,1) both;\n        }\n        .hero-btns { display:flex; gap:8px; flex-wrap:wrap; margin-bottom:.6rem; animation:heroTitleIn .8s .3s cubic-bezier(.34,1.56,.64,1) both; }\n        .btn-hp {\n          background:#fbbf24; color:#3b0764; border:none; padding:12px 24px; border-radius:10px;\n          font-family:\'Space Grotesk\',sans-serif; font-size:14px; font-weight:800; cursor:pointer;\n          box-shadow:0 4px 20px rgba(251,191,36,.4); transition:.2s;\n        }\n        .btn-hp:hover { background:#d97706; transform:translateY(-2px); }\n        .btn-hs {\n          background:rgba(255,255,255,.08); color:#fff; border:1.5px solid rgba(255,255,255,.35);\n          padding:11px 22px; border-radius:10px; font-family:\'Space Grotesk\',sans-serif;\n          font-size:14px; font-weight:700; cursor:pointer; transition:.15s;\n        }\n        .btn-hs:hover { border-color:#67e8f9; color:#67e8f9; }\n        .hero-stats { display:flex; gap:1.25rem; }\n        .hstat-num { font-size:1rem; font-weight:800; color:#fbbf24; }\n        .hstat-lbl { font-size:10px; color:rgba(255,255,255,.5); }\n        .hero-ads { display:grid; grid-template-columns:1fr 1fr; gap:.5rem; align-content:start; }\n        .hero-ads-center { display:flex; flex-direction:column; gap:.5rem; align-self:center; }\n        .hero-timer { height:2px; background:rgba(255,255,255,.12); border-radius:2px; overflow:hidden; margin-top:4px; }\n        .hero-timer-bar { height:100%; background:#fbbf24; border-radius:2px; transition:width .5s linear; }\n        @media(max-width:1400px) {\n          .hero-inner { grid-template-columns:1fr 360px !important; }\n          .hero-ads-left, .hero-ads-right, .hero-ads-center { display:none !important; }\n        }\n        @media(max-width:768px) {\n          .hero-inner { grid-template-columns:1fr !important; }\n          .hero-product-col { max-height:320px; overflow:hidden; }\n        }\n      `}</style>\n\n      {/* Orbs */}\n      <div className="hero-orb ho1" />\n      <div className="hero-orb ho2" />\n      <div className="hero-orb ho3" />\n\n      <div className="hero-inner">\n        {/* Col 1: Left Ads */}\n        <div className="hero-ads-left">\n          <div className="hero-ads">\n            {leftAds.map((ad, i) => <HeroAdCard key={i} ad={ad} />)}\n          </div>\n          <div className="hero-timer">\n            <div className="hero-timer-bar" style={{ width: `${(tick / 16) * 100}%` }} />\n          </div>\n        </div>\n\n        {/* Col 2: Hero Text */}\n        <div className="hero">\n          <div className="hero-tag">🌍 World&apos;s First Social Shopping Canvas</div>\n          <h1>\n            Draw it.<br/>\n            <span className="hc">Find it.</span><br/>\n            <span className="hg">Buy it.</span>\n          </h1>\n          <p className="hero-sub">\n            Sketch your wishlist on a real-time collaborative canvas,\n            drag real products onto it, and shop with friends — all in one place.\n          </p>\n          <div className="hero-btns">\n            <button className="btn-hp">🎨 Start Drawing Free</button>\n            <button className="btn-hs" onClick={onShare} style={{border:\'1.5px solid #fbbf24\'}}>Invite Friends</button>\n          </div>\n          <div className="hero-stats">\n            <div>\n              <div className="hstat-num">10K+</div>\n              <div className="hstat-lbl">Active Canvases</div>\n            </div>\n            <div>\n              <div className="hstat-num">500K+</div>\n              <div className="hstat-lbl">Products</div>\n            </div>\n            <div>\n              <div className="hstat-num">50K+</div>\n              <div className="hstat-lbl">Happy Shoppers</div>\n            </div>\n          </div>\n        </div>\n\n        {/* Col 3: Center Ads */}\n        <div className="hero-ads-center">\n          {centerAds.map((ad, i) => (\n            <div\n              key={i}\n              style={{ background: \'rgba(255,255,255,.09)\', border: \'1px solid rgba(255,255,255,.15)\', borderRadius: \'12px\', overflow: \'hidden\', cursor: \'pointer\' }}\n              onClick={() => window.open(ad.url, \'_blank\')}\n            >\n              <img src={ad.img} alt={ad.name} width="140" height="68" style={{ width: \'100%\', height: \'68px\', objectFit: \'cover\', display: \'block\' }} />\n              <div style={{ padding: \'.35rem .5rem\' }}>\n                <div style={{ fontSize: \'.65rem\', fontWeight: \'700\', color: \'#fff\', whiteSpace: \'nowrap\', overflow: \'hidden\', textOverflow: \'ellipsis\' }}>{ad.name}</div>\n                <div style={{ fontSize: \'.75rem\', fontWeight: \'800\', color: \'#fbbf24\' }}>{ad.price}</div>\n              </div>\n            </div>\n          ))}\n        </div>\n\n        {/* Col 4: Mini Canvas */}\n        <div className="hero-product-col">\n          <MiniCanvas />\n        </div>\n\n        {/* Col 5: Right Ads */}\n        <div className="hero-ads-right hero-product-col">\n          <div className="hero-ads">\n            {rightAds.map((ad, i) => <HeroAdCard key={i} ad={ad} />)}\n          </div>\n          <div className="hero-timer">\n            <div className="hero-timer-bar" style={{ width: `${(tick / 16) * 100}%` }} />\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\Hero.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/Hero.jsx")

# src/components/MiniFloatingCanvas.jsx
content = 'import { useState, useRef } from \'react\';\nimport { useNavigate } from \'react-router-dom\';\nimport { useCanvasStore } from \'../store/canvas\';\nimport CanvasOverlayLayer from \'./CanvasOverlayLayer\';\nimport VoiceRecorder from \'./VoiceRecorder\';\nimport AudioMessage from \'./AudioMessage\';\n\nexport default function MiniFloatingCanvas() {\n  const canvasRef = useRef(null);\n  const [minimized, setMinimized] = useState(false);\n  const [drawing, setDrawing] = useState(false);\n  const navigate = useNavigate();\n  const addCard  = useCanvasStore(s => s.addCard);\n  const [destination, setDestination] = useState(\'everyone\');\n  const [pendingProduct, setPendingProduct] = useState(null);\n  const [showRoomPicker, setShowRoomPicker] = useState(false);\n  const [confirmMsg, setConfirmMsg] = useState(\'\');\n  const [miniAudios, setMiniAudios] = useState([]);\n  const containerRef = useRef(null);\n\n  const MOCK_ROOMS = [\n    { id: \'room-1\', name: \'Family Shopping\', online: [\'Anna\', \'Maja\'], isOnline: true },\n    { id: \'room-2\', name: \'My Wishlist\',     online: [],              isOnline: false },\n    { id: \'room-3\', name: \'Spring Fashion\',  online: [\'Erik\'],        isOnline: true },\n  ];\n\n  const handleDrop = (e) => {\n    e.preventDefault();\n    const raw = e.dataTransfer.getData(\'application/drawnbuy-product\');\n    if (!raw) return;\n    let product;\n    try { product = JSON.parse(raw); } catch { return; }\n    if (destination === \'everyone\') {\n      addCard(\'main-collab\', {\n        id: Date.now().toString(), product,\n        x: 80 + Math.random() * 250, y: 60 + Math.random() * 180, ownerId: \'mini-guest\',\n      });\n      setConfirmMsg(\'Added to main canvas!\');\n      setTimeout(() => setConfirmMsg(\'\'), 2500);\n    } else {\n      setPendingProduct(product);\n      setShowRoomPicker(true);\n    }\n  };\n\n  const dropToRoom = (room) => {\n    if (!pendingProduct) return;\n    addCard(room.id, {\n      id: Date.now().toString(), product: pendingProduct,\n      x: 60 + Math.random() * 160, y: 40 + Math.random() * 120, ownerId: \'mini-guest\',\n    });\n    setShowRoomPicker(false);\n    setPendingProduct(null);\n    setConfirmMsg(\'Added to \' + room.name + \'!\');\n    setTimeout(() => setConfirmMsg(\'\'), 2500);\n  };\n\n  const onMiniAudio = (url, dur) => setMiniAudios(m => [...m, { url, dur, id: Date.now() }]);\n  const [tool, setTool] = useState(\'draw\');\n  const lastPos = useRef(null);\n\n  const getPos = (e, canvas) => {\n    const r = canvas.getBoundingClientRect();\n    const scaleX = canvas.width / r.width;\n    const scaleY = canvas.height / r.height;\n    const src = e.touches ? e.touches[0] : e;\n    return { x: (src.clientX - r.left) * scaleX, y: (src.clientY - r.top) * scaleY };\n  };\n\n  const startDraw = e => {\n    e.preventDefault();\n    const canvas = canvasRef.current;\n    if (!canvas) return;\n    setDrawing(true);\n    lastPos.current = getPos(e, canvas);\n  };\n\n  const doDraw = e => {\n    if (!drawing) return;\n    const canvas = canvasRef.current;\n    const ctx = canvas.getContext(\'2d\');\n    const pos = getPos(e, canvas);\n    ctx.beginPath();\n    if (tool === \'erase\') {\n      ctx.globalCompositeOperation = \'destination-out\';\n      ctx.lineWidth = 16;\n    } else {\n      ctx.globalCompositeOperation = \'source-over\';\n      ctx.strokeStyle = \'#7c3aed\';\n      ctx.lineWidth = 3;\n    }\n    ctx.lineCap = \'round\';\n    ctx.moveTo(lastPos.current.x, lastPos.current.y);\n    ctx.lineTo(pos.x, pos.y);\n    ctx.stroke();\n    lastPos.current = pos;\n  };\n\n  const endDraw = () => setDrawing(false);\n\n  const clearCanvas = () => {\n    const canvas = canvasRef.current;\n    if (canvas) canvas.getContext(\'2d\').clearRect(0, 0, canvas.width, canvas.height);\n  };\n\n  return (\n    <div style={{\n      position: \'fixed\',\n      bottom: \'20px\',\n      right: \'20px\',\n      zIndex: 300,\n      filter: \'drop-shadow(0 8px 32px rgba(124,58,237,.35))\',\n    }}>\n      <style>{`\n        @keyframes floatIn { from{opacity:0;transform:scale(.8) translateY(20px)} to{opacity:1;transform:none} }\n        .mfc-wrap { animation:floatIn .4s cubic-bezier(.34,1.56,.64,1); }\n        .mfc-btn { background:none; border:none; color:rgba(255,255,255,.7); cursor:pointer; font-size:12px; padding:2px 6px; border-radius:4px; transition:.15s; font-family:inherit; font-weight:700; }\n        .mfc-btn:hover { background:rgba(255,255,255,.15); color:#fff; }\n        .mfc-chip { background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.15); color:rgba(255,255,255,.8); border-radius:6px; padding:4px 8px; font-size:10px; font-weight:700; cursor:pointer; font-family:inherit; transition:.1s; }\n        .mfc-chip.on,.mfc-chip:hover { background:rgba(251,191,36,.22); border-color:#fbbf24; color:#fbbf24; }\n      `}</style>\n\n      {minimized ? (\n        /* Collapsed pill */\n        <button\n          onClick={() => setMinimized(false)}\n          style={{\n            background: \'linear-gradient(135deg,#7c3aed,#5b21b6)\',\n            border: \'2px solid rgba(251,191,36,.4)\',\n            borderRadius: \'50px\',\n            padding: \'10px 16px\',\n            color: \'#fff\',\n            cursor: \'pointer\',\n            fontFamily: \'inherit\',\n            fontSize: \'13px\',\n            fontWeight: \'800\',\n            display: \'flex\',\n            alignItems: \'center\',\n            gap: \'6px\',\n            boxShadow: \'0 4px 20px rgba(124,58,237,.5)\',\n          }}\n        >\n          🎨 Canvas\n          <span style={{ background: \'#22c55e\', width: \'8px\', height: \'8px\', borderRadius: \'50%\', display: \'inline-block\' }} />\n        </button>\n      ) : (\n        /* Expanded canvas */\n        <div\n          className="mfc-wrap"\n          style={{ background: \'linear-gradient(135deg,#3b0764,#5b21b6)\', borderRadius: \'16px\', overflow: \'hidden\', width: \'240px\', border: \'2px solid rgba(251,191,36,.3)\' }}\n        >\n          {/* Header */}\n          <div style={{ background: \'rgba(0,0,0,.3)\', padding: \'7px 10px\', display: \'flex\', alignItems: \'center\', gap: \'6px\' }}>\n            <span style={{ background: \'#ef4444\', color: \'#fff\', fontSize: \'9px\', fontWeight: \'800\', padding: \'2px 7px\', borderRadius: \'20px\', display: \'flex\', alignItems: \'center\', gap: \'3px\' }}>\n              <span style={{ width: \'4px\', height: \'4px\', borderRadius: \'50%\', background: \'#fff\', display: \'inline-block\' }} /> LIVE\n            </span>\n            <span style={{ fontSize: \'11px\', color: \'rgba(255,255,255,.65)\', fontWeight: \'600\', flex: 1 }}>Mini Canvas</span>\n            <button className="mfc-btn" onClick={clearCanvas}>🗑</button>\n            <button className="mfc-btn" onClick={() => setMinimized(true)}>–</button>\n          </div>\n\n          {/* Canvas */}\n          <div style={{ background: \'#fff\', height: \'150px\', position: \'relative\', cursor: tool === \'erase\' ? \'cell\' : \'crosshair\' }}>\n            \n        {/* Destination toggle */}\n        <div style={{ display:\'flex\', gap:4, padding:\'5px 8px\', borderBottom:\'1px solid rgba(255,255,255,.1)\', flexShrink:0 }}>\n          {[\'everyone\',\'rooms\'].map(opt => (\n            <button key={opt} onClick={() => setDestination(opt)} style={{ flex:1, padding:\'3px 0\', borderRadius:6, border:\'1.5px solid\', borderColor: destination===opt?\'#fbbf24\':\'rgba(255,255,255,.15)\', background: destination===opt?\'#fbbf24\':\'transparent\', color: destination===opt?\'#1a0a3e\':\'rgba(255,255,255,.7)\', fontSize:\'.65rem\', fontWeight:700, cursor:\'pointer\' }}>\n              {opt === \'everyone\' ? \'Everyone\' : \'My Rooms\'}\n            </button>\n          ))}\n        </div>\n        {confirmMsg && <div style={{ background:\'#d1fae5\', color:\'#065f46\', fontSize:\'.68rem\', fontWeight:700, padding:\'3px 8px\', textAlign:\'center\' }}>{confirmMsg}</div>}\n        {showRoomPicker && (\n          <div style={{ position:\'absolute\', bottom:\'100%\', right:0, marginBottom:6, background:\'#fff\', borderRadius:12, padding:\'10px\', width:220, boxShadow:\'0 8px 32px rgba(0,0,0,.25)\', border:\'1.5px solid #fbbf24\', zIndex:500 }}>\n            <div style={{ fontSize:\'.78rem\', fontWeight:800, color:\'#1a0a3e\', marginBottom:6 }}>Choose a room</div>\n            {MOCK_ROOMS.map(room => (\n              <button key={room.id} onClick={() => dropToRoom(room)} style={{ width:\'100%\', display:\'flex\', alignItems:\'center\', gap:6, padding:\'7px 8px\', borderRadius:8, border:\'1px solid #f3f4f6\', background:\'#fafafa\', cursor:\'pointer\', marginBottom:3, fontFamily:\'inherit\' }}>\n                <div style={{ width:7, height:7, borderRadius:\'50%\', background: room.isOnline?\'#22c55e\':\'#d1d5db\', flexShrink:0 }}/>\n                <div style={{ flex:1, textAlign:\'left\' }}>\n                  <div style={{ fontSize:\'.75rem\', fontWeight:700, color:\'#1a0a3e\' }}>{room.name}</div>\n                  {room.online.length > 0 && <div style={{ fontSize:\'.6rem\', color:\'#9ca3af\' }}>{room.online.join(\', \')} online</div>}\n                </div>\n              </button>\n            ))}\n            <button onClick={() => {setShowRoomPicker(false); setPendingProduct(null);}} style={{ width:\'100%\', padding:\'5px\', borderRadius:8, border:\'1px solid #f3f4f6\', background:\'#fff\', color:\'#9ca3af\', fontSize:\'.7rem\', cursor:\'pointer\', fontFamily:\'inherit\' }}>Cancel</button>\n          </div>\n        )}\n        <div\n          ref={containerRef}\n          style={{ position: \'relative\', flex: 1 }}\n          onDragOver={(e) => e.preventDefault()}\n          onDrop={handleDrop}\n        >\n          <canvas\n              ref={canvasRef}\n              width={240}\n              height={150}\n              style={{ position: \'absolute\', inset: 0, width: \'100%\', height: \'100%\' }}\n              onMouseDown={startDraw}\n              onMouseMove={doDraw}\n              onMouseUp={endDraw}\n              onMouseLeave={endDraw}\n              onTouchStart={startDraw}\n              onTouchMove={doDraw}\n              onTouchEnd={endDraw}\n            />\n          <CanvasOverlayLayer canvasId="mini-preview" />\n        </div>\n            <div style={{ position: \'absolute\', inset: 0, display: \'flex\', alignItems: \'center\', justifyContent: \'center\', pointerEvents: \'none\' }}>\n              <span style={{ fontSize: \'11px\', color: \'rgba(124,58,237,.2)\', fontWeight: \'600\' }}>✏️ Quick draw here</span>\n            </div>\n          </div>\n\n          {/* Toolbar */}\n          <div style={{ background: \'rgba(0,0,0,.2)\', padding: \'6px 8px\', display: \'flex\', gap: \'4px\', alignItems: \'center\' }}>\n            <button className={`mfc-chip ${tool === \'draw\' ? \'on\' : \'\'}`} onClick={() => setTool(\'draw\')}>✏️</button>\n            <button className={`mfc-chip ${tool === \'erase\' ? \'on\' : \'\'}`} onClick={() => setTool(\'erase\')}>🧹</button>\n            \n        {miniAudios.length > 0 && (\n          <div style={{ padding:\'4px 8px\', borderTop:\'1px solid rgba(255,255,255,.1)\' }}>\n            {miniAudios.slice(-1).map(a => (\n              <AudioMessage key={a.id} url={a.url} duration={a.dur} sender="You" time="" isMe={true}/>\n            ))}\n          </div>\n        )}\n        <div style={{ padding:\'4px 8px\', borderTop:\'1px solid rgba(255,255,255,.1)\' }}>\n          <VoiceRecorder canvasId="mini-canvas" onAudioReady={onMiniAudio} userName="You"/>\n        </div>\n        <button\n              style={{ marginLeft: \'auto\', background: \'rgba(251,191,36,.2)\', border: \'1px solid rgba(251,191,36,.3)\', color: \'#fbbf24\', borderRadius: \'6px\', padding: \'4px 8px\', fontSize: \'10px\', fontWeight: \'700\', cursor: \'pointer\', fontFamily: \'inherit\' }}\n              onClick={() => document.getElementById(\'collabSection\')?.scrollIntoView({ behavior: \'smooth\' })}\n            >↑ Open Full</button>\n          </div>\n        </div>\n      )}\n    </div>\n  );\n}\n'
os.makedirs(r"src\\components", exist_ok=True)
open(r"src\\components\\MiniFloatingCanvas.jsx", "w", encoding="utf-8").write(content)
print("Done: src/components/MiniFloatingCanvas.jsx")

# src/pages/HomePage.jsx
content = "import { useState } from 'react';\nimport AdStrip from '../components/AdStrip';\nimport Hero from '../components/Hero';\nimport CategoryBar from '../components/CategoryBar';\nimport CollabCanvas from '../components/CollabCanvas';\nimport DragStrip from '../components/DragStrip';\nimport ProductSearchPanel from '../components/ProductSearchPanel';\nimport DealsGrid from '../components/DealsGrid';\nimport CategoriesGrid from '../components/CategoriesGrid';\nimport Sponsors from '../components/Sponsors';\nimport HowItWorks from '../components/HowItWorks';\nimport Footer from '../components/Footer';\n\nexport default function HomePage() {\n  const [activeCategory, setActiveCategory] = useState('all');\n\n  return (\n    <>\n      <AdStrip />\n      <Hero onShare={() => setShareOpen(true)} />\n      <CategoryBar onSelect={setActiveCategory} />\n      <CollabCanvas />\n      <DragStrip />\n      <ProductSearchPanel />\n      <DealsGrid selectedCategory={activeCategory} />\n      <Sponsors />\n      <CategoriesGrid />\n      <HowItWorks />\n      <Footer />\n    </>\n  );\n}\n"
os.makedirs(r"src\\pages", exist_ok=True)
open(r"src\\pages\\HomePage.jsx", "w", encoding="utf-8").write(content)
print("Done: src/pages/HomePage.jsx")

